VALUES
  ('optometrist-moex-03084', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '大明以文章式視力表所測得的近距離視力，右眼可在30 cm看到6M的文字，左眼可在30 cm看到3M的 文字，則其優眼的視力為：', '["0.05", "0.1", "0.2", "0.18"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "8ad68996080b", "answer_pdf_sha1": "a56e9b214439", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03085', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '承上題，若大明想要流暢地閱讀課本上約2M大小的文字，請問大明所需的等效放大度數（等效閱讀屈光 度，equivalent viewing power）約為：', '["4～5 D", "10～12 D", "15～16 D", "20～22 D"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "8ad68996080b", "answer_pdf_sha1": "a56e9b214439", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03086', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '承上題，請問大明的等效閱讀距離（equivalent viewing distance, EVD）為何？', '["約10 cm", "約20 cm", "約30 cm", "約40 cm"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "8ad68996080b", "answer_pdf_sha1": "a56e9b214439", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03087', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '在為左側偏盲的視野缺損患者配鏡時，可以用Fresnel稜鏡貼在眼鏡上來輔助，有關使用方法的敘述，下 列何者正確？', '["在鏡片左半邊貼上基底朝右的稜鏡", "在鏡片右半邊貼上基底朝左的稜鏡", "在鏡片左半邊貼上基底朝左的稜鏡", "在鏡片左半邊貼上基底朝右的稜鏡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "8ad68996080b", "answer_pdf_sha1": "a56e9b214439", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03088', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '一位70歲低視力患者，他在25 cm處可測得20/60的最佳矯正視力，若其希望能閱讀約當近視力表上20/20 大小字體的雜誌，他的老花眼鏡至少應需多少度數？', '["+6 D", "+8 D", "+12 D", "+20 D"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "8ad68996080b", "answer_pdf_sha1": "a56e9b214439", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03089', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '一個配備+25 D物鏡和+50 D目鏡的天文望遠鏡（astronomical telescope），望遠鏡長度約為6 cm，放大 倍率為-2X ，若一位近視-5 D的患者，在不戴眼鏡的狀況下想使用此望遠鏡，並且不想改變物鏡和目鏡的 度數下，則望遠鏡的長度應該為多少？此時放大倍率為何？', '["望遠鏡長度為5.8 cm，放大倍率為-2.2X", "望遠鏡長度為6.2 cm，放大倍率為-1.8X", "望遠鏡長度為5.8 cm，放大倍率為2.2X", "望遠鏡長度為6.2 cm，放大倍率為1.8X"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "8ad68996080b", "answer_pdf_sha1": "a56e9b214439", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03090', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '一位老花眼患者戴著+2 D的老花眼鏡（+2 D near addition），坐在離閉路電視50 cm的地方，使用 閉路電視將原物體放大6X，若以參考距離（reference distance）25 cm來看，則此影像被放大的幾倍 （total enlargement）？', '["1X", "1.5X", "2X", "3X"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "8ad68996080b", "answer_pdf_sha1": "a56e9b214439", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03091', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '低視力患者在視力檢查或驗光時，下列敘述何者正確？', '["宜使用較小的度數間隔，如相差0.12 D的球面或散光度數或交叉圓柱鏡等，讓病患比較其差異", "一般的視力表可移近使用，如正常在6 m使用的視力表，可移近到2 m用，若在2 m得到的驗光度數 為-1.75 D，需修正為遠用度數-1.25 D", "低視力患者驗光後發現有無配戴眼鏡的視力均同，即裸視視力與最佳矯正視力相同時，如患者度數較 深，不用輔具時建議配戴矯正眼鏡", "低視力者通常矯正視力不佳，在使用輔具時，則無需配戴矯正眼鏡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "8ad68996080b", "answer_pdf_sha1": "a56e9b214439", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03092', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '低視力患者使用放大鏡或望遠鏡將視網膜影像放大的原理為：', '["尺寸放大（increase object size）", "距離調整（adjust viewing distance）", "實物投影放大（real image magnification）", "鏡片放大（telescopic magnification）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "8ad68996080b", "answer_pdf_sha1": "a56e9b214439", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03093', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有一低視力者，使用望遠鏡時，將其反向使用（將原本接目鏡向遠方，接物鏡向眼前），則他可能是下 列那種病患？', '["糖尿病玻璃體出血", "末期青光眼", "全熟型白內障（white cataract）", "大疱性角膜水腫（bullous keratopathy）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "8ad68996080b", "answer_pdf_sha1": "a56e9b214439", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
